15	library ieee;
16	use ieee.std_logic_1164.all;
17	
18	library surf;
19	use surf.StdRtlPkg.all;
20	
21	entity SynchronizerEdge is
22	   generic (
23	      TPD_G          : time     := 1 ns;
24	      RST_POLARITY_G : sl       := '1';  -- '1' for active HIGH reset, '0' for active LOW reset
25	      OUT_POLARITY_G : sl       := '1';  -- 0 for active LOW, 1 for active HIGH
26	      RST_ASYNC_G    : boolean  := false;  -- Reset is asynchronous
27	      BYPASS_SYNC_G  : boolean  := false;  -- Bypass Synchronizer module for synchronous data configuration
28	      STAGES_G       : positive := 3;
29	      INIT_G         : slv      := "0");
30	   port (
31	      clk         : in  sl;             -- clock to be SYNC'd to
32	      rst         : in  sl := not RST_POLARITY_G;  -- Optional reset
33	      dataIn      : in  sl;             -- Data to be 'synced'
34	      dataOut     : out sl;             -- synced data
35	      risingEdge  : out sl;             -- Rising edge detected
36	      fallingEdge : out sl);            -- Falling edge detected
37	end SynchronizerEdge;
38	
39	architecture rtl of SynchronizerEdge is
40	
41	   constant INIT_C : slv(STAGES_G-1 downto 0) := ite(INIT_G = "0", slvZero(STAGES_G), INIT_G);
42	
43	   type RegType is record
44	      syncDataDly : sl;
45	      dataOut     : sl;
46	      risingEdge  : sl;
47	      fallingEdge : sl;
48	   end record RegType;
49	   constant REG_INIT_C : RegType := (
50	      syncDataDly => '0',
51	      dataOut     => (not OUT_POLARITY_G),
52	      risingEdge  => (not OUT_POLARITY_G),
53	      fallingEdge => (not OUT_POLARITY_G));
54	
55	   signal r   : RegType := REG_INIT_C;
56	   signal rin : RegType;
57	
58	   signal syncData : sl;
59	
60	begin
61	
62	   assert (STAGES_G >= 3) report "STAGES_G must be >= 3" severity failure;
63	
64	   Synchronizer_Inst : entity surf.Synchronizer
65	      generic map (
66	         TPD_G          => TPD_G,
67	         RST_POLARITY_G => RST_POLARITY_G,
68	         OUT_POLARITY_G => '1',
69	         RST_ASYNC_G    => RST_ASYNC_G,
70	         STAGES_G       => (STAGES_G-1),
71	         BYPASS_SYNC_G  => BYPASS_SYNC_G,
72	         INIT_G         => INIT_C(STAGES_G-2 downto 0))
73	      port map (
74	         clk     => clk,
75	         rst     => rst,
76	         dataIn  => dataIn,
77	         dataOut => syncData);
78	
79	   comb : process (r, rst, syncData) is
80	      variable v : RegType;
81	   begin
82	      -- Latch the current value
83	      v := r;
84	
85	      -- Reset strobe signals
86	      v.risingEdge  := not OUT_POLARITY_G;
87	      v.fallingEdge := not OUT_POLARITY_G;
88	
89	      -- Keep a record of the last syncData
90	      v.syncDataDly := syncData;
91	
92	      -- Set the polarity of the output
93	      if (OUT_POLARITY_G = '1') then
94	         v.dataOut := syncData;
95	      else
96	         v.dataOut := not(syncData);
97	      end if;
98	
99	      -- Check for a rising edge of the syncData
100	      if (syncData = '1') and (r.syncDataDly = '0') then
101	         v.risingEdge := OUT_POLARITY_G;
102	      end if;
103	
104	      -- Check for a rising edge of the syncData
105	      if (syncData = '0') and (r.syncDataDly = '1') then
106	         v.fallingEdge := OUT_POLARITY_G;
107	      end if;
108	
109	      -- Sync Reset
110	      if (RST_ASYNC_G = false and rst = RST_POLARITY_G) then
111	         v             := REG_INIT_C;
112	         v.syncDataDly := syncData;     -- prevent accidental edge detection
113	      end if;
