115	      -- Register the variable for next clock cycle
116	      rin <= v;
117	
118	      -- Outputs
119	      dataOut     <= r.dataOut;
120	      risingEdge  <= r.risingEdge;
121	      fallingEdge <= r.fallingEdge;
122	
123	   end process comb;
